/**
 * ScrollTrigger Mock - Version minimale pour FootTracker
 * (Utilisez la vraie librairie GSAP ScrollTrigger en production)
 * 
 * Cette version minimaliste permet de faire fonctionner les animations
 * au scroll sans la librairie complète.
 */

if (typeof gsap !== 'undefined') {
  class ScrollTriggerMock {
    static create(config) {
      const { trigger, start, toggleActions, scrub } = config;
      const element = typeof trigger === 'string' ? document.querySelector(trigger) : trigger;
      
      if (!element) return;
      
      const observer = new IntersectionObserver((entries) => {
        entries.forEach(entry => {
          if (entry.isIntersecting && config.onEnter) {
            config.onEnter();
          }
        });
      }, {
        threshold: 0.1,
        rootMargin: '0px 0px -15% 0px'
      });
      
      observer.observe(element);
      return { kill: () => observer.disconnect() };
    }
    
    static maxScroll(window) {
      return document.documentElement.scrollHeight - window.innerHeight;
    }
  }
  
  if (!window.ScrollTrigger) {
    window.ScrollTrigger = ScrollTriggerMock;
    gsap.registerPlugin = gsap.registerPlugin || function() {};
    console.log('📦 ScrollTrigger Mock chargé (version simplifiée)');
  }
}
